    exit 1
fi
echo "[SUCCESS] Dependensi berhasil disinkronkan."
echo ""

# в”Ђв”Ђ STEP 3: MENGUNDUH BROWSER UNTUK PLAYWRIGHT в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
if [ ! -f ".venv/.installed" ]; then
    echo "[INFO] Mengunduh browser Chromium untuk otomatisasi Grab/Shopee..."
    uv run python -m playwright install chromium
    
    if [ $? -ne 0 ]; then
        echo "[ERROR] Gagal mengunduh browser Chromium!"
        read -p "Tekan [Enter] untuk keluar..."
        exit 1
    fi
    echo "Sukses diinstal pada $(date)" > .venv/.installed
    echo "[SUCCESS] Browser Chromium berhasil diinstal!"
    echo ""
fi

# в”Ђв”Ђ STEP 4: JALANKAN PROGRAM UTAMA в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
# Force Headful mode for local run (so staff can solve OTP/CAPTCHAs)
export HEADLESS=false

while true; do
    echo "================================================================="
    echo "                   MENJALANKAN INTERAKTIF CLI"
    echo "================================================================="
    echo ""
    uv run python cli.py

    echo ""
    echo "================================================================="
    echo "                     PROSES SELESAI"
    echo "================================================================="
    echo ""
    
    echo "[INFO] Mengunggah CSV terbaru ke Drive & push ke Master..."
    uv run python src/upload_csv_to_drive_and_git.py
    echo ""
    
    read -p "Apakah Anda ingin Lanjut (l) atau Keluar (k)? [L/K]: " choice
    case "$choice" in
        [lL]|[yY]*)
            echo ""
            echo "[INFO] Memulai kembali program..."
            echo ""
            clear
            ;;
        *)
            echo "[INFO] Keluar dari program. Sampai jumpa!"
            break
            ;;
    esac
done
